// MARK: - HMAC Signing

struct RequestSigner {
    let apiKey: String
    let apiSecret: String

    func sign(method: String, path: String, body: Data?, timestamp: String) -> String {
        let bodyHash = SHA256.hash(data: body ?? Data())
        let bodyHex = bodyHash.compactMap { String(format: "%02x", $0) }.joined()
        let payload = "\(timestamp)\n\(method.uppercased())\n\(path)\n\(bodyHex)"
        let key = SymmetricKey(data: Data(apiSecret.utf8))
        let sig = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(sig).base64EncodedString()
    }
}

