        let cleanPath = path.hasPrefix("/") ? String(path.dropFirst()) : path
        components.path = basePath + cleanPath
        if !query.isEmpty { components.queryItems = query }
        guard let url = components.url else { throw AppError.invalidURL }
        return url
    }

    func request<T: Decodable>(
        _ method: String,
        _ path: String,
        query: [URLQueryItem] = [],
        body: Encodable? = nil,
        additionalHeaders: [String: String] = [:]
    ) async throws -> T {
        let url = try makeURL(path, query: query)
        var req = URLRequest(url: url)
        req.httpMethod = method
        req.timeoutInterval = 20
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")

        if let token = auth.accessToken {
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let apiKey = config.apiKey {
            req.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        }

        var bodyData: Data? = nil
        if let body = body {
            bodyData = try TradingJSON.encoder.encode(AnyEncodable(body))
            req.httpBody = bodyData
        }

        let timestamp = "\(Int(Date().timeIntervalSince1970))"
        req.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")

        if let signer = secure.signer {
            let pathWithQuery = url.path + (url.query.map { "?\($0)" } ?? "")
            let signature = signer.sign(method: method, path: pathWithQuery, body: bodyData, timestamp: timestamp)
            req.setValue(signature, forHTTPHeaderField: "X-Signature")
        }

        for (k, v) in additionalHeaders {
            req.setValue(v, forHTTPHeaderField: k)
        }

        let (data, response) = try await session.data(for: req)
        guard let http = response as? HTTPURLResponse else { throw AppError.network("No response.") }

        if http.statusCode == 401 { throw AppError.unauthorized }
        if !(200...299).contains(http.statusCode) {
            let message = (try? JSONSerialization.jsonObject(with: data)) as? [String: Any]
            let msg = message?["message"] as? String
            throw AppError.server(status: http.statusCode, message: msg)
        }

        do {
            return try TradingJSON.decoder.decode(T.self, from: data)
        } catch {
            throw AppError.decoding
        }
    }

    func requestVoid(
        _ method: String,
        _ path: String,
        query: [URLQueryItem] = [],
        body: Encodable? = nil
    ) async throws {
        let _: EmptyResponse = try await request(method, path, query: query, body: body)
    }
}

