// MARK: - Certificate Pinning (SPKI hash)

final class PinningDelegate: NSObject, URLSessionDelegate {
    private let pinnedSPKIHashes: Set<String>

    init(pinnedSPKIHashes: Set<String>) {
        self.pinnedSPKIHashes = pinnedSPKIHashes
    }

    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let trust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }

        var error: CFError?
        guard SecTrustEvaluateWithError(trust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        guard let cert = SecTrustGetCertificateAtIndex(trust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        let spkiHash = Self.spkiSHA256Base64(of: cert)
        if let spkiHash, pinnedSPKIHashes.contains(spkiHash) {
            completionHandler(.useCredential, URLCredential(trust: trust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }

    private static func spkiSHA256Base64(of certificate: SecCertificate) -> String? {
        guard let key = SecCertificateCopyKey(certificate) else { return nil }
        var error: Unmanaged<CFError>?
        guard let keyData = SecKeyCopyExternalRepresentation(key, &error) as Data? else { return nil }
        let digest = SHA256.hash(data: keyData)
        return Data(digest).base64EncodedString()
    }
}

// MARK: - Services

protocol TradingService {
    func fetchPortfolio() async throws -> PortfolioSnapshot
    func fetchQuote(symbol: String) async throws -> StockQuote
    func executeTrade(_ order: OrderRequest) async throws -> OrderResponse
    func cancelOrder(orderId: String) async throws
    func streamQuotes(symbols: [String]) -> AsyncStream<StockQuote>
}

final class LiveTradingService: TradingService {
    private let client: APIClient
    init(client: APIClient) { self.client = client }

    func fetchPortfolio() async throws -> PortfolioSnapshot {
        try await client.request("GET", "/v1/portfolio")
    }

    func fetchQuote(symbol: String) async throws -> StockQuote {
        try await client.request("GET", "/v1/market/quote", query: [URLQueryItem(name: "symbol", value: symbol)])
    }

    func executeTrade(_ order: OrderRequest) async throws -> OrderResponse {
        try await client.request("POST", "/v1/orders", body: order)
    }

    func cancelOrder(orderId: String) async throws {
        try await client.requestVoid("DELETE", "/v1/orders/\(orderId)")
    }

    func streamQuotes(symbols: [String]) -> AsyncStream<StockQuote> {
        AsyncStream { continuation in
            let task = Task {
                var last: [String: StockQuote] = [:]
                while !Task.isCancelled {
                    for sym in symbols {
                        do {
                            let q = try await fetchQuote(symbol: sym)
                            if last[sym] != q {
                                last[sym] = q
                                continuation.yield(q)
                            }
                        } catch {
                            // Silent retry to keep stream alive.
                        }
                    }
                    try? await Task.sleep(nanoseconds: 900_000_000)
                }
                continuation.finish()
            }
            continuation.onTermination = { _ in task.cancel() }
        }
    }
}

