final class MockTradingService: TradingService {
    private var quotes: [String: StockQuote] = [:]
    private var portfolio: PortfolioSnapshot
    private var lastOrderId: Int = 1000

    init() {
        let now = Date()
        let summary = PortfolioSummary(
            equity: 250_000,
            cash: 50_000,
            buyingPower: 100_000,
            dayPnl: 1_250,
            totalPnl: 18_500
        )
        let positions: [Position] = [
            Position(symbol: "AAPL", quantity: 120, avgCost: 165.20, marketPrice: 180.10, marketValue: 21_612, unrealizedPnl: 1_788, unrealizedPnlPercent: 8.99),
            Position(symbol: "TSLA", quantity: 40, avgCost: 210.00, marketPrice: 195.50, marketValue: 7_820, unrealizedPnl: -580, unrealizedPnlPercent: -6.90),
            Position(symbol: "MSFT", quantity: 60, avgCost: 310.00, marketPrice: 326.75, marketValue: 19_605, unrealizedPnl: 1_005, unrealizedPnlPercent: 5.40)
        ]
        self.portfolio = PortfolioSnapshot(summary: summary, positions: positions, timestamp: now)

        quotes["AAPL"] = StockQuote(symbol: "AAPL", price: 180.10, change: 1.22, changePercent: 0.68, timestamp: now)
        quotes["TSLA"] = StockQuote(symbol: "TSLA", price: 195.50, change: -2.10, changePercent: -1.06, timestamp: now)
        quotes["MSFT"] = StockQuote(symbol: "MSFT", price: 326.75, change: 0.85, changePercent: 0.26, timestamp: now)
        quotes["NVDA"] = StockQuote(symbol: "NVDA", price: 910.20, change: 12.40, changePercent: 1.38, timestamp: now)
        quotes["SPY"] = StockQuote(symbol: "SPY", price: 520.14, change: 0.44, changePercent: 0.08, timestamp: now)
    }

    func fetchPortfolio() async throws -> PortfolioSnapshot {
        portfolio
    }

    func fetchQuote(symbol: String) async throws -> StockQuote {
        let sym = symbol.uppercased()
        let now = Date()
        let base = quotes[sym] ?? StockQuote(symbol: sym, price: Decimal.fromDouble(Double.random(in: 20...450)), change: 0, changePercent: 0, timestamp: now)
        let drift = Decimal.fromDouble(Double.random(in: -0.8...0.8))
        let newPrice = max(Decimal(0.01), (base.price + drift).rounded(scale: 2))
        let chg = (newPrice - base.price).rounded(scale: 2)
        let chgPct = base.price == 0 ? 0 : ((chg / base.price) * 100).rounded(scale: 2)
        let q = StockQuote(symbol: sym, price: newPrice, change: chg, changePercent: chgPct, timestamp: now)
        quotes[sym] = q
        return q
    }

    func executeTrade(_ order: OrderRequest) async throws -> OrderResponse {
        let sym = order.symbol.uppercased()
        guard order.quantity > 0 else { throw AppError.validation("Quantity must be greater than 0.") }
        if order.type == .limit {
            guard let lp = order.limitPrice, lp > 0 else { throw AppError.validation("Limit price is required for limit orders.") }
        }

        let quote = try await fetchQuote(symbol: sym)
        let fillPrice: Decimal = {
            switch order.type {
            case .market:
                return quote.price
            case .limit:
                let lp = order.limitPrice ?? quote.price
                if order.side == .buy { return min(lp, quote.price) }
                return max(lp, quote.price)
            }
        }().rounded(scale: 2)

        let filledQty = order.quantity
        let notional = (filledQty * fillPrice).rounded(scale: 2)

        var summary = portfolio.summary
        var positions = portfolio.positions

        func upsertPosition(symbol: String, deltaQty: Decimal, fill: Decimal) throws {
            if let idx = positions.firstIndex(where: { $0.symbol == symbol }) {
                let p = positions[idx]
                let newQty = p.quantity + deltaQty
                if newQty < 0 { throw AppError.validation("Insufficient shares to sell.") }
                if newQty == 0 {
                    positions.remove(at: idx)
                    return
                }
                let newAvg: Decimal
                if deltaQty > 0 {
                    let totalCost = (p.avgCost * p.quantity) + (fill * deltaQty)
                    newAvg = (totalCost / newQty).rounded(scale: 4)
                } else {
                    newAvg = p.avgCost
                }
                let market = quote.price
                let mv = (newQty * market).rounded(scale: 2)
                let unreal = ((market - newAvg) * newQty).rounded(scale: 2)
                let unrealPct = newAvg == 0 ? 0 : (((market - newAvg) / newAvg) * 100).rounded(scale: 2)
                positions[idx] = Position(symbol: symbol, quantity: newQty, avgCost: newAvg, marketPrice: market, marketValue: mv, unrealizedPnl: unreal, unrealizedPnlPercent: unrealPct)
            } else {
                if deltaQty < 0 { throw AppError.validation("No position to sell.") }
                let newQty = deltaQty
                let avg = fill.rounded(scale: 4)
                let market = quote.price
                let mv = (newQty * market).rounded(scale: 2)
                let unreal = ((market - avg) * newQty).rounded(scale: 2)
                let unrealPct = avg == 0 ? 0 : (((market - avg) / avg) * 100).rounded(scale: 2)
                positions.append(Position(symbol: symbol, quantity: newQty, avgCost: avg, marketPrice: market, marketValue: mv, unrealizedPnl: unreal, unrealizedPnlPercent: unrealPct))
            }
        }

        switch order.side {
        case .buy:
            if summary.buyingPower < notional { throw AppError.validation("Insufficient buying power.") }
            summary.cash = (summary.cash - notional).rounded(scale: 2)
            summary.buyingPower = (summary.buyingPower - notional).rounded(scale: 2)
            try upsertPosition(symbol: sym, deltaQty: filledQty, fill: fillPrice)
        case .sell:
            try upsertPosition(symbol: sym, deltaQty: -filledQty, fill: fillPrice)
            summary.cash = (summary.cash + notional).rounded(scale: 2)
            summary.buyingPower = (summary.buyingPower + notional).rounded(scale: 2)
        }

        let equity = (summary.cash + positions.reduce(Decimal(0)) { $0 + $1.marketValue }).rounded(scale: 2)
        summary.equity = equity

        portfolio = PortfolioSnapshot(summary: summary, positions: positions.sorted(by: { $0.marketValue > $1.marketValue }), timestamp: Date())

        lastOrderId += 1
        return OrderResponse(
            id: "\(lastOrderId)",
            symbol: sym,
            side: order.side,
            type: order.type,
            quantity: order.quantity,
            filledQuantity: filledQty,
            avgFillPrice: fillPrice,
            status: .filled,
            message: "Filled",
            timestamp: Date()
        )
    }

    func cancelOrder(orderId: String) async throws { }

    func streamQuotes(symbols: [String]) -> AsyncStream<StockQuote> {
        AsyncStream { continuation in
            let task = Task {
                while !Task.isCancelled {
                    for sym in symbols {
                        if let q = try? await fetchQuote(symbol: sym) {
                            continuation.yield(q)
                        }
                    }
                    try? await Task.sleep(nanoseconds: 700_000_000)
                }
                continuation.finish()
            }
            continuation.onTermination = { _ in task.cancel() }
        }
    }
}

// MARK: - App State

@MainActor
final class TradingStore: ObservableObject {
    @Published var portfolio: PortfolioSnapshot? = nil
    @Published var watchlist: [String] = ["AAPL", "TSLA", "MSFT", "NVDA", "SPY"]
    @Published var quotes: [String: StockQuote] = [:]
    @Published var activity: [ActivityEvent] = []
    @Published var isLoadingPortfolio: Bool = false
    @Published var lastError: AppError? = nil
    @Published var connected: Bool = true

    private let service: TradingService
    private var quoteTask: Task<Void, Never>? = nil

    init(service: TradingService) {
        self.service = service
    }

    func start() {
        loadPortfolio()
        startQuotes()
    }

    func stop() {
        quoteTask?.cancel()
        quoteTask = nil
    }

    func loadPortfolio() {
        isLoadingPortfolio = true
        Task {
            defer { isLoadingPortfolio = false }
            do {
                let p = try await service.fetchPortfolio()
                portfolio = p
                addActivity(.info, "Portfolio updated", "Equity \(p.summary.equity.toCurrency())")
                lastError = nil
            } catch {
                let e = (error as? AppError) ?? .unknown(error.localizedDescription)
                lastError = e
                addActivity(.error, "Portfolio refresh failed", e.localizedDescription)
            }
        }
    }

    func startQuotes() {
        quoteTask?.cancel()
        let symbols = watchlist
        quoteTask = Task {
            for await q in service.streamQuotes(symbols: symbols) {
                quotes[q.symbol] = q
                connected = true
            }
        }
    }

    func execute(order: OrderRequest) {
        Task {
            do {
                let resp = try await service.executeTrade(order)
                addActivity(.success, "\(resp.side.rawValue.uppercased()) \(resp.symbol)", "Filled \(resp.filledQuantity.toString(maxFraction: 6)) @ \((resp.avgFillPrice ?? 0).toCurrency())")
                await refreshAfterTrade()
                lastError = nil
            } catch {
                let e = (error as? AppError) ?? .unknown(error.localizedDescription)
                lastError = e
                addActivity(.error, "Order failed", e.localizedDescription)
            }
        }
    }

    private func refreshAfterTrade() async {
        do {
            let p = try await service.fetchPortfolio()
            portfolio = p
        } catch {
            // non-fatal
        }
    }

    func addToWatchlist(_ symbol: String) {
        let sym = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard sym.count >= 1 else { return }
        if !watchlist.contains(sym) {
            watchlist.insert(sym, at: 0)
            addActivity(.info, "Added to watchlist", sym)
            startQuotes()
        }
    }

    func removeFromWatchlist(_ symbol: String) {
        watchlist.removeAll { $0 == symbol }
        quotes.removeValue(forKey: symbol)
        addActivity(.info, "Removed from watchlist", symbol)
        startQuotes()
    }

    private func addActivity(_ kind: ActivityEvent.Kind, _ title: String, _ detail: String) {
        activity.insert(ActivityEvent(id: UUID().uuidString, title: title, detail: detail, date: Date(), kind: kind), at: 0)
        if activity.count > 50 { activity.removeLast(activity.count - 50) }
    }
}

