struct TradingView: View {
    @EnvironmentObject var store: TradingStore

    @State private var symbol: String = "AAPL"
    @State private var side: OrderSide = .buy
    @State private var type: OrderType = .market
    @State private var quantityText: String = "1"
    @State private var limitText: String = ""
    @State private var isConfirmPresented: Bool = false

    var quote: StockQuote? { store.quotes[symbol.uppercased()] }

    var body: some View {
        NavigationStack {
            Form {
                Section {
                    VStack(alignment: .leading, spacing: 10) {
                        HStack(alignment: .firstTextBaseline) {
                            TextField("Symbol", text: $symbol)
                                .textInputAutocapitalization(.characters)
                                .autocorrectionDisabled()
                                .onChange(of: symbol) { _, newValue in
                                    let cleaned = newValue.uppercased().filter { $0.isLetter || $0.isNumber || $0 == "." || $0 == "-" }
                                    if cleaned != newValue { symbol = cleaned }
                                }
                            Button("Add") { store.addToWatchlist(symbol) }
                                .buttonStyle(.bordered)
                        }

                        if let q = quote {
                            QuoteCard(quote: q)
                        } else {
                            Text("No quote yet. Add to watchlist or wait for updates.")
                                .foregroundStyle(.secondary)
                                .font(.footnote)
                        }
                    }
                }

                Section("Order") {
                    Picker("Side", selection: $side) {
                        ForEach(OrderSide.allCases) { s in
                            Text(s.rawValue.capitalized).tag(s)
                        }
                    }
                    Picker("Type", selection: $type) {
                        ForEach(OrderType.allCases) { t in
                            Text(t.rawValue.capitalized).tag(t)
                        }
                    }
                    TextField("Quantity", text: $quantityText)
                        .keyboardType(.decimalPad)

                    if type == .limit {
                        TextField("Limit Price", text: $limitText)
                            .keyboardType(.decimalPad)
                    }

                    HStack {
                        Button("Preview") { isConfirmPresented = true }
                            .buttonStyle(.borderedProminent)
                            .disabled(!canPreview)
                        Spacer()
                        Button("Refresh Portfolio") { store.loadPortfolio() }
                            .buttonStyle(.bordered)
                    }
                }

                Section("Quick Actions") {
                    WatchlistRow(symbols: store.watchlist, quotes: store.quotes) { selected in
                        symbol = selected
                    } onRemove: { sym in
                        store.removeFromWatchlist(sym)
                    }
                }

                if let p = store.portfolio {
                    Section("Buying Power") {
                        LabeledContent("Cash", value: p.summary.cash.toCurrency())
                        LabeledContent("Buying Power", value: p.summary.buyingPower.toCurrency())
                    }
                }
            }
            .navigationTitle("Trade")
            .sheet(isPresented: $isConfirmPresented) {
                TradeConfirmSheet(
                    symbol: symbol.uppercased(),
                    side: side,
                    type: type,
                    quantityText: quantityText,
                    limitText: limitText,
                    quote: quote,
                    portfolio: store.portfolio,
                    onExecute: { order in
                        store.execute(order: order)
                        isConfirmPresented = false
                    },
                    onCancel: { isConfirmPresented = false }
                )
                .presentationDetents([.medium, .large])
            }
        }
    }

    var canPreview: Bool {
        let sym = symbol.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sym.isEmpty else { return false }
        guard Decimal(string: quantityText.replacingOccurrences(of: ",", with: ".")) != nil else { return false }
        if type == .limit {
            guard Decimal(string: limitText.replacingOccurrences(of: ",", with: ".")) != nil else { return false }
        }
        return true
    }
}

struct TradeConfirmSheet: View {
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantityText: String
    let limitText: String
    let quote: StockQuote?
    let portfolio: PortfolioSnapshot?
    let onExecute: (OrderRequest) -> Void
    let onCancel: () -> Void

    @State private var validationError: String? = nil
    @State private var clientOrderId: String = UUID().uuidString

    var body: some View {
        NavigationStack {
            List {
                Section("Preview") {
                    LabeledContent("Symbol", value: symbol)
                    LabeledContent("Side", value: side.rawValue.capitalized)
                    LabeledContent("Type", value: type.rawValue.capitalized)
                    LabeledContent("Quantity", value: (qty?.toString(minFraction: 0, maxFraction: 6) ?? "-"))
                    if type == .limit {
                        LabeledContent("Limit", value: (limit?.toCurrency() ?? "-"))
                    }
                }

                Section("Market") {
                    if let q = quote {
                        LabeledContent("Last", value: q.price.toCurrency())
                        if let c = q.change, let p = q.changePercent {
                            let sign = c >= 0 ? "+" : ""
                            LabeledContent("Change", value: "\(sign)\(c.toString()) (\(sign)\(p.toString())%)")
                                .foregroundStyle(c >= 0 ? .green : .red)
                        }
                        LabeledContent("As of", value: q.timestamp.formatted(date: .abbreviated, time: .standard))
                    } else {
                        Text("Quote unavailable. Market orders may fill at current market.")
                            .foregroundStyle(.secondary)
                            .font(.footnote)
                    }
                }

                Section("Estimated") {
                    LabeledContent("Est. Notional", value: estNotional.toCurrency())
                    if let bp = portfolio?.summary.buyingPower {
                        let remaining = (bp - estNotional).rounded(scale: 2)
                        LabeledContent("Est. Remaining BP", value: remaining.toCurrency())
                            .foregroundStyle(remaining >= 0 ? .primary : .red)
                    }
                }

                if let validationError {
                    Section {
                        Text(validationError)
                            .foregroundStyle(.red)
                            .font(.callout)
                    }
                }
            }
            .navigationTitle("Confirm Order")
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { onCancel() }
                }
                ToolbarItem(placement: .confirmationAction) {
                    Button(side == .buy ? "Place Buy" : "Place Sell") {
                        place()
                    }
                    .disabled(qty == nil || (type == .limit && limit == nil))
                }
            }
        }
        .onAppear { validate() }
        .onChange(of: quantityText) { _, _ in validate() }
        .onChange(of: limitText) { _, _ in validate() }
    }

    var qty: Decimal? {
        Decimal(string: quantityText.replacingOccurrences(of: ",", with: "."))
    }

    var limit: Decimal? {
        Decimal(string: limitText.replacingOccurrences(of: ",", with: "."))
    }

    var estPrice: Decimal {
        if type == .limit, let l = limit { return l }
        return quote?.price ?? 0
    }

    var estNotional: Decimal {
        guard let q = qty else { return 0 }
        return (q * estPrice).rounded(scale: 2)
    }

    func validate() {
        validationError = nil
        guard let q = qty, q > 0 else { validationError = "Quantity must be greater than 0."; return }
        if type == .limit {
            guard let l = limit, l > 0 else { validationError = "Limit price must be greater than 0."; return }
        }
        if let p = portfolio {
            if side == .buy && p.summary.buyingPower < estNotional {
                validationError = "Estimated notional exceeds buying power."
            }
        }
    }

    func place() {
        validate()
        if validationError != nil { return }
        let order = OrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: qty ?? 0,
            limitPrice: type == .limit ? limit : nil,
            clientOrderId: clientOrderId
        )
        onExecute(order)
    }
}

struct QuoteCard: View {
    let quote: StockQuote
    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(alignment: .firstTextBaseline) {
                Text(quote.symbol)
                    .font(.headline)
                Spacer()
                Text(quote.price.toCurrency())
                    .font(.title3)
                    .monospacedDigit()
            }
            if let c = quote.change, let p = quote.changePercent {
                let sign = c >= 0 ? "+" : ""
                Text("\(sign)\(c.toString())  \(sign)\(p.toString())%")
                    .font(.subheadline)
                    .foregroundStyle(c >= 0 ? .green : .red)
            }
            Text("Updated \(quote.timestamp.formatted(date: .omitted, time: .standard))")
                .font(.caption)
                .foregroundStyle(.secondary)
        }
        .padding(12)
        .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 14, style: .continuous))
    }
}

struct WatchlistRow: View {
    let symbols: [String]
    let quotes: [String: StockQuote]
    let onSelect: (String) -> Void
    let onRemove: (String) -> Void

    var body: some View {
        if symbols.isEmpty {
            Text("Watchlist is empty.")
                .foregroundStyle(.secondary)
        } else {
            ForEach(symbols, id: \.self) { sym in
                Button {
                    onSelect(sym)
                } label: {
                    HStack {
                        VStack(alignment: .leading) {
                            Text(sym).font(.headline)
                            if let q = quotes[sym] {
                                Text(q.timestamp.formatted(date: .omitted, time: .standard))
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            }
                        }
                        Spacer()
                        if let q = quotes[sym] {
                            VStack(alignment: .trailing) {
                                Text(q.price.toCurrency())
                                    .monospacedDigit()
                                if let c = q.change {
                                    let sign = c >= 0 ? "+" : ""
                                    Text("\(sign)\(c.toString())")
                                        .font(.caption)
                                        .foregroundStyle(c >= 0 ? .green : .red)
                                }
                            }
                        } else {
                            Text("—")
                                .foregroundStyle(.secondary)
                        }
                    }
                }
                .swipeActions {
                    Button(role: .destructive) { onRemove(sym) } label: { Text("Remove") }
                }
            }
        }
    }
}

