struct PositionRow: View {
    let position: Position
    let quote: StockQuote?

    var body: some View {
        let marketPrice = quote?.price ?? position.marketPrice
        let mv = (position.quantity * marketPrice).rounded(scale: 2)
        let unreal = ((marketPrice - position.avgCost) * position.quantity).rounded(scale: 2)
        let unrealPct = position.avgCost == 0 ? 0 : (((marketPrice - position.avgCost) / position.avgCost) * 100).rounded(scale: 2)

        return HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text(position.symbol).font(.headline)
                Text("\(position.quantity.toString(minFraction: 0, maxFraction: 6)) @ \(position.avgCost.toCurrency())")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 4) {
                Text(mv.toCurrency())
                    .monospacedDigit()
                let sign = unreal >= 0 ? "+" : ""
                Text("\(sign)\(unreal.toCurrency())  \(sign)\(unrealPct.toString())%")
                    .font(.caption)
                    .foregroundStyle(unreal >= 0 ? .green : .red)
                    .monospacedDigit()
            }
        }
    }
}

