struct ErrorBanner: View {
    let error: AppError
    let dismiss: () -> Void

    var body: some View {
        HStack(spacing: 10) {
            Image(systemName: "exclamationmark.triangle.fill")
                .foregroundStyle(.white)
            Text(error.localizedDescription)
                .foregroundStyle(.white)
                .font(.callout)
                .lineLimit(2)
            Spacer(minLength: 8)
            Button(action: dismiss) {
                Image(systemName: "xmark.circle.fill")
                    .foregroundStyle(.white.opacity(0.9))
            }
            .buttonStyle(.plain)
        }
        .padding(12)
        .background(Color.red.opacity(0.92), in: RoundedRectangle(cornerRadius: 14, style: .continuous))
        .shadow(radius: 8, y: 4)
    }
}

// MARK: - App Entry

@main
struct TradingApp: App {
    @StateObject private var auth = AuthSession()
    @StateObject private var store: TradingStore

    init() {
        let useMock = true

        if useMock {
            let service = MockTradingService()
            _store = StateObject(wrappedValue: TradingStore(service: service))
        } else {
            let config = APIConfig.default
            let authSession = AuthSession()

            let secure = APIClient.SecureConfig(
                pinnedSPKIHashes: [
                    // Populate with your server SPKI SHA256 Base64 pins.
                    // Example: "m0nZ0rQv...="
                ],
                signer: nil
                // signer: RequestSigner(apiKey: "<key>", apiSecret: "<secret>")
            )

            let client = APIClient(config: config, auth: authSession, secure: secure)
            let service = LiveTradingService(client: client)
            _store = StateObject(wrappedValue: TradingStore(service: service))
        }
    }

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(store)
                .environmentObject(auth)
        }
    }
}